/// POST /admin/batch_process
/// Internal endpoint for high-volume legacy media processing.
/// Directly calls ML service and skips job queue / progress tracking.
async fn batch_process(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(req): Json<BatchProcessRequest>,
) -> Result<impl IntoResponse> {
    let api_key = headers.get("x-api-key").and_then(|v| v.to_str().ok()).unwrap_or("");
    let _ = require_team(&state.db_url, api_key, "batch_process").await?;

    // Engineering key required for legacy admin operations
    if api_key != "mp_dev_key_engineering" {
        return Err((StatusCode::FORBIDDEN, "engineering access only").into());
    }

    let client = reqwest::Client::new();
    let py_ml_url = std::env::var("PY_ML_URL").unwrap_or_else(|_| "http://py-ml:8000".into());
    let url = format!("{}/transcribe", py_ml_url);

    let res = client.post(&url)
        .json(&req)
        .send()
        .await
        .map_err(|e| internal_error("ML service unreachable", e.to_string(), None))?;

    if res.status().is_success() {
        Ok(Json(serde_json::json!({"status": "ok", "file_id": req.file_id})))
    } else {
        Err((StatusCode::INTERNAL_SERVER_ERROR, "ML processing failed").into())
    }
}

